import React from 'react';
import { List, ListItem, ListItemText, TextField, Typography, Slider, Box } from '@mui/material';
import { shapeDefinitions, defaultShape } from '../shapes';

const Sidebar = ({
  selectedShape,
  onShapeSelect,
  shapeParams,
  onParamChange,
  color,
  onColorChange,
  lineWidth,
  onLineWidthChange,
  mousePos
}) => {
  return (
    <div className="sidebar">
      <List>
        {Object.entries(shapeDefinitions).map(([key, shape]) => (
          <ListItem
            button
            key={key}
            selected={selectedShape === key}
            onClick={() => onShapeSelect(key)}
          >
            <ListItemText primary={shape.text} />
          </ListItem>
        ))}
      </List>

      {selectedShape !== defaultShape && (
        <Box sx={{ p: 2 }}>
          {shapeDefinitions[selectedShape].params.map(param => (
            <TextField
              key={param.name}
              label={param.label}
              type="number"
              value={shapeParams[param.name] || ''}
              onChange={(e) => onParamChange(param.name, e.target.value)}
              fullWidth
              margin="normal"
              size="small"
            />
          ))}
          <TextField
            label="Color"
            type="color"
            value={color}
            onChange={(e) => onColorChange(e.target.value)}
            fullWidth
            margin="normal"
            size="small"
          />
          <Typography gutterBottom>Line Width</Typography>
          <Slider
            value={lineWidth}
            onChange={(_, value) => onLineWidthChange(value)}
            min={1}
            max={10}
            step={1}
            marks
          />
          <Box sx={{ mt: 2 }}>
            <Typography variant="body2">
              Mouse Position: ({mousePos.x.toFixed(0)}, {mousePos.y.toFixed(0)})
            </Typography>
          </Box>
        </Box>
      )}
    </div>
  );
};

export default Sidebar;
